-- 文化科普类
INSERT INTO `ai_training_knowledge` (`title`, `content`, `category`, `source_type`, `tags`, `status`, `admin_id`, `created_at`) VALUES
('符籙的基本概念', '符籙是道教法術的重要組成部分，是書寫在紙張、布帛或木板上的圖形或符號，被認為具有神秘的力量。符籙通常由道士書寫，使用特殊的墨水（常用朱砂），配合特定的咒語和儀式。\n\n符籙的種類繁多，包括：\n1. 護身符：用於保護人身安全\n2. 鎮宅符：用於驅邪避凶\n3. 招財符：用於招攬財運\n4. 姻緣符：用於增進感情姻緣\n5. 平安符：用於保佑平安順遂', 'culture', 'text', '["符籙", "道教", "法術"]', 'ready', 1, NOW()),

('符水的使用方法', '符水是道教法事中常用的法物，將符籙焚化後溶於水中而成。\n\n使用方法：\n1. 將符籙對著太陽方向豎立，口中默唸咒語\n2. 用火（最好用蠟燭或檀香）將符籙從上往下燃燒\n3. 燃燒後的符灰放入乾淨的杯中\n4. 加入適量清水（最好是礦泉水或陰陽水）\n5. 用筷子或樹枝（最好是柳枝或桃枝）順時針攪拌三次\n6. 讓求符者飲用或用於擦拭身體\n\n注意事項：\n- 符水最好在24小時內使用\n- 孕婦及小孩使用前應諮詢專業人士\n- 符水並非萬能，應保持理性', 'usage', 'text', '["符水", "使用方法", "道教"]', 'ready', 1, NOW()),

('一物一證制度', '符寶網的「一物一證」制度是確保商品真偽的重要認證機制。\n\n認證內容：\n1. 每件商品都有獨立的認證編號\n2. 商品配有專業機構的檢測證書\n3. 可通過二維碼或編號查詢驗證\n4. 證書包含商品的詳細信息及師傅資料\n\n驗證方式：\n1. 掃描商品上的二維碼\n2. 在符寶網輸入認證編號\n3. 查看商品詳細資訊及認證記錄\n\n為什麼重要：\n- 確保購買到正品\n- 追溯商品來源\n- 保障消費者權益', 'product', 'text', '["一物一證", "認證", "正品"]', 'ready', 1, NOW()),

('如何選擇適合的護身符', '選擇護身符時應考慮以下因素：\n\n1. 需求類型\n   - 事業：選擇文昌符、官運符\n   - 財運：選擇招財符、五路財神符\n   - 健康：選擇平安符、壽星符\n   - 感情：選擇姻緣符、和合符\n\n2. 個人八字\n   - 應配合個人八字五行選擇\n   - 避免與命格相沖的符籙\n\n3. 佩戴方式\n   - 随身佩戴：小型符卡或符袋\n   - 居家擺放：大型符畫或符帖\n   - 車用：車掛符或擋風玻璃符\n\n4. 開光與否\n   - 建議選擇已開光的符籙\n   - 開光後的符籙能量更強', 'product', 'text', '["護身符", "選擇", "選購指南"]', 'ready', 1, NOW()),

('風水命理基礎概念', '風水是我國傳統文化的重要組成部分，主要研究環境與人的關係。\n\n基本概念：\n1. 氣：風水中最核心的概念，指環境中的能量\n2. 龍脈：地勢的走向，代表能量的流動\n3. 穴位：氣聚集的關鍵位置\n4. 陰陽：一切事物的兩個相對面\n5. 五行：金、木、水、火、土\n\n常用方位：\n- 東：代表事業與成長\n- 南：代表名聲與地位\n- 西：代表財運與子孫\n- 北：代表事業與智慧\n\n實用建議：\n- 臥室應避免直沖大門\n- 書桌宜靠牆不宜對窗\n- 爐灶不宜對著水槽', 'fortune', 'text', '["風水", "命理", "五行"]', 'ready', 1, NOW()),

('符籙的歷史演變', '符籙的歷史可追溯至遠古時期，經歷了漫長的發展歷程。\n\n遠古時期：\n- 以圖騰和符號為主\n- 與巫術緊密結合\n\n先秦時期：\n- 開始形成系統化的符號體系\n- 與道家思想融合\n\n漢代：\n- 道教正式形成\n- 符籙成為道教法術的核心\n- 出現《太平經》等典籍記載\n\n魏晉南北朝：\n- 符籙種類大幅增加\n- 形成不同派系的符法\n- 上清派、靈寶派等各有特色\n\n唐宋時期：\n- 符籙文化達到鼎盛\n- 官方與民間廣泛使用\n- 出現大量符籙典籍\n\n明清時期：\n- 符籙趨於民間化\n- 形成各地特色符法\n- 傳承方式以師徒為主', 'culture', 'text', '["歷史", "符籙演變", "道教文化"]', 'ready', 1, NOW()),

('常見的驅邪鎮宅符', '驅邪鎮宅類符籙是道教法器中最常見的類別之一。\n\n太上鎮宅符：\n- 用於驅除家中邪祟\n- 宜貼於大門或客廳\n- 需配合儀式開光\n\n五雷驅邪符：\n- 專門驅趕不良氣場\n- 適用於煞氣較重的場所\n- 建議由專業道士處理\n\n安宅符：\n- 用於穩定家宅氣場\n- 促進家庭和睦\n- 適合新居入伙使用\n\n土地符：\n- 供奉土地公使用的符\n- 祈求土地保佑\n- 常見於傳統店鋪\n\n使用注意：\n- 符籙應保持乾燥\n- 避免沾染污穢\n- 定期更換以保持效力', 'culture', 'text', '["驅邪符", "鎮宅符", "道教法器"]', 'ready', 1, NOW()),

('八字命盤基礎解讀', '八字命盤是根據一個人的出生年月日時推算出來的命運分析工具。\n\n構成要素：\n1. 年柱：祖上及少年時期\n2. 月柱：青年時期及手足\n3. 日柱：中年時期及配偶\n4. 時柱：晚年時期及子女\n\n五行分析：\n- 了解命格五行屬性\n- 分析五行旺衰\n- 判斷喜用神\n\n十神含義：\n- 比肩、劫財：兄弟姐妹、同事\n- 食神、傷官：才華、子女\n- 正財、偏財：財運、金錢\n- 正官、七殺：事業、官非\n- 正印、偏印：學業、母親\n\n實用建議：\n- 建議諮詢專業命理師\n- 命運並非固定不變\n- 努力同樣重要', 'fortune', 'text', '["八字", "命盤", "命理"]', 'ready', 1, NOW());

