INSERT INTO `ai_qa_pairs` (`question`, `answer`, `category`, `keywords`, `is_active`, `created_at`) VALUES
('什麼是符籙？', '符籙是道教法術的重要組成部分，是書寫在紙張、布帛或木板上的圖形或符號，被認為具有神秘的力量。符籙通常由道士書寫，使用特殊的墨水（常用朱砂），配合特定的咒語和儀式。符籙的種類繁多，包括護身符、鎮宅符、招財符、姻緣符、平安符等。', 'culture', '["符籙", "道教", "法術"]', 1, NOW()),

('符水如何使用？', '符水的使用方法：\n1. 將符籙對著太陽方向豎立，口中默唸咒語\n2. 用火（最好用蠟燭或檀香）將符籙從上往下燃燒\n3. 燃燒後的符灰放入乾淨的杯中\n4. 加入適量清水（最好是礦泉水或陰陽水）\n5. 用筷子或樹枝（最好是柳枝或桃枝）順時針攪拌三次\n6. 讓求符者飲用或用於擦拭身體\n\n符水最好在24小時內使用，孕婦及小孩使用前應諮詢專業人士。', 'usage', '["符水", "使用", "方法"]', 1, NOW()),

('什麼是一物一證？', '符寶網的「一物一證」制度是確保商品真偽的重要認證機制。每件商品都有獨立的認證編號，配有專業機構的檢測證書，可通過二維碼或編號查詢驗證。這個制度可以確保您購買到正品，追溯商品來源，保障消費者權益。', 'product', '["一物一證", "認證", "正品"]', 1, NOW()),

('如何選擇護身符？', '選擇護身符時應考慮：\n\n1. 需求類型：事業選文昌符、財運選招財符、健康選平安符\n2. 個人八字：應配合個人五行選擇，避免與命格相沖\n3. 佩戴方式：隨身佩戴選小型符卡，居家擺放選大型符畫\n4. 開光與否：建議選擇已開光的符籙，效果更佳\n\n如有疑問，建議諮詢我們的客服或專業人士。', 'product', '["護身符", "選擇", "選購"]', 1, NOW()),

('符籙有效期限是多久？', '符籙的有效期限取決於以下因素：\n\n1. 符籙種類：不同類型的符籙有效期不同\n2. 開光方式：正式道觀開光的符籙通常效力更持久\n3. 保存方式：保持乾燥、避免污穢可延長有效期\n4. 使用頻率：經常使用的符籙可能需要定期更換\n\n一般建議：\n- 護身符佩戴1-2年後更換\n- 鎮宅符3-5年更換一次\n- 如有損壞或汙染應立即更換', 'usage', '["有效期", "符籙", "更換"]', 1, NOW()),

('哪些符可以放在車上？', '適合放在車上的符籙包括：\n\n1. 車掛符：專為車輛設計的符籙\n2. 平安符：祈求行車安全\n3. 擋煞符：阻擋路上煞氣\n4. 財運符：利於生意出行\n\n放置位置建議：\n- 後視鏡下方\n- 車前端內飾板上\n- 副駕駛座前方\n\n注意事項：\n- 符籙應保持正面朝上\n- 避免陽光直射\n- 定期檢查是否有損壞', 'usage', '["車用符", "汽車", "平安"]', 1, NOW()),

('道教的起源？', '道教的起源可追溯至遠古時期的巫術和鬼神崇拜，正式形成於東漢時期（約公元142年），由張道陵創立的五斗米道被視為道教的開端。\n\n發展歷程：\n- 遠古時期：自然崇拜與巫術\n- 先秦時期：道家思想形成\n- 東漢：道教正式建立\n- 魏晉：迅速發展期\n- 唐宋：鼎盛時期\n- 明清：民間化時期\n\n道教融合了道家哲學、神仙信仰、鬼神崇拜等元素，形成獨特的文化體系。', 'culture', '["道教", "起源", "歷史"]', 1, NOW()),

('風水的基本概念？', '風水是我國傳統文化的重要組成部分，主要研究環境與人的關係。\n\n核心概念：\n1. 氣：環境中的能量\n2. 龍脈：地勢走向\n3. 穴位：氣聚集的關鍵位置\n4. 陰陽：事物的兩個相對面\n5. 五行：金、木、水、火、土\n\n常用方位：\n- 東：事業與成長\n- 南：名聲與地位\n- 西：財運與子孫\n- 北：事業與智慧\n\n實用建議：臥室避免直沖大門，書桌宜靠牆。', 'fortune', '["風水", "五行", "方位"]', 1, NOW());
